/**
 * Notification model and core types for the notification system.
 *
 * Architecture: Event-driven via EventBus.
 * - Services emit domain events (e.g., order:created) to EventBus
 * - NotificationService subscribes to relevant events
 * - NotificationService dispatches to registered NotificationAdapters
 *
 * Constraints:
 * - All notification triggers must go through EventBus.emit()
 * - All delivery channels must implement NotificationAdapter
 * - NotificationService is the sole bridge between events and adapters
 */

export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

export type NotificationChannel = 'email' | 'sms' | 'in_app' | 'webhook';

export type NotificationStatus = 'pending' | 'sent' | 'failed';

export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  type: NotificationType;
  metadata?: Record<string, unknown>;
}

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  type: NotificationType;
  status: NotificationStatus;
  metadata?: Record<string, unknown>;
  createdAt: Date;
  sentAt?: Date;
}

/**
 * Result returned by a NotificationAdapter after attempting delivery.
 */
export interface NotificationResult {
  success: boolean;
  notificationId: string;
  channel: NotificationChannel;
  error?: string;
}

/**
 * Interface that all notification delivery adapters must implement.
 *
 * To add a new notification channel:
 * 1. Create a class implementing NotificationAdapter in src/adapters/
 * 2. Register it with NotificationService via registerAdapter()
 *
 * Adapters are responsible for actual delivery (email sending, SMS API, etc.).
 * The NotificationService handles event subscription and adapter dispatch.
 */
export interface NotificationAdapter {
  readonly channel: NotificationChannel;
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Currently a stub that stores emails in-memory for testing.
 * Replace the send() internals with a real email provider (e.g., SendGrid, SES)
 * when ready — the interface contract stays the same.
 */

import type {
  NotificationAdapter,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);

    return {
      success: true,
      notificationId: '', // filled in by NotificationService
      channel: this.channel,
    };
  }

  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — event-driven notification dispatch.
 *
 * Architecture: ALL notifications flow through the EventBus.
 * - This service subscribes to domain events (order:created, order:status-changed, etc.)
 * - It maps events to NotificationPayloads
 * - It dispatches payloads to registered NotificationAdapters
 *
 * Constraints:
 * - No direct service calls for triggering notifications. All triggers come via EventBus.
 * - All delivery channels must implement the NotificationAdapter interface.
 * - Register adapters via registerAdapter() before emitting events.
 *
 * To add a new notification trigger:
 * 1. Define the event type in src/events/event-types.ts
 * 2. Add a handler method in this service that maps the event to a NotificationPayload
 * 3. Subscribe to the event in registerEventHandlers()
 *
 * To add a new delivery channel:
 * 1. Implement NotificationAdapter in src/adapters/
 * 2. Register it with this service via registerAdapter()
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../events/event-types.js';
import type {
  Notification,
  NotificationAdapter,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported; later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all domain events that should trigger notifications.
   * All event subscriptions go through EventBus — no direct callbacks.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) =>
      this.handleOrderCreated(event),
    );

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) =>
      this.handleOrderStatusChanged(event),
    );

    this.eventBus.on<UserCreatedEvent>('user:created', (event) =>
      this.handleUserCreated(event),
    );
  }

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.dispatch({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
      type: 'order_confirmation',
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.dispatch({
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
      type: 'order_status_update',
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.dispatch({
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro!`,
      channel: 'email',
      type: 'welcome',
      metadata: { userId: event.user.id },
    });
  }

  /**
   * Dispatch a notification payload to the appropriate adapter.
   * Records the notification and its delivery result.
   */
  async dispatch(payload: NotificationPayload): Promise<NotificationResult> {
    const id = generateNotificationId();
    const notification: Notification = {
      id,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      type: payload.type,
      status: 'pending',
      metadata: payload.metadata,
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(payload.channel);
    if (!adapter) {
      this.logger.warn(`No adapter registered for channel: ${payload.channel}`);
      notification.status = 'failed';
      this.notifications.push(notification);
      return { success: false, notificationId: id, channel: payload.channel, error: `No adapter for channel: ${payload.channel}` };
    }

    const result = await adapter.send(payload);
    result.notificationId = id;

    notification.status = result.success ? 'sent' : 'failed';
    if (result.success) {
      notification.sentAt = new Date();
    }
    this.notifications.push(notification);

    this.logger.info(`Notification ${id} ${notification.status} via ${payload.channel}`);
    return result;
  }

  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  getNotificationsByType(type: NotificationType): Notification[] {
    return this.notifications.filter((n) => n.type === type);
  }

  getNotificationCount(): number {
    return this.notifications.length;
  }

  clearNotifications(): void {
    this.notifications = [];
  }
}

